import type { RequestHandler } from 'express';

import config = require('../config/countries.json');

declare global {
  namespace Express {
    interface Request {
      /**
       * Country data for the current request.
       * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-country_config#countryconfigmiddleware | Documentation}
       */
      country?: CountryConfig.Country;
    }
  }
}

type GetCountryFunction = (
  countryId: CountryConfig.CountryId,
) => CountryConfig.Country;

type Countries = Record<CountryConfig.CountryId, CountryConfig.Country>;

interface CountryConfigExport extends GetCountryFunction {
  /**
   * Get country data for a specific country.
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-country_config#usage}
   */
  getCountryConfig: GetCountryFunction;

  /**
   * Express middleware that sets the country data in the request object.
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-country_config#countryconfigmiddleware}
   */
  middleware: RequestHandler;

  /**
   * Get country data for all countries.
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-country_config#countryconfiggetcountriesdata}
   */
  getCountriesData: () => Countries;
}

/**
 * @deprecated Use named import instead.
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-country_config | Documentation}
 * @example
 * ```js
 * import { countryConfig } from 'nordic/country-config';
 * ```
 */
declare const CountryConfig: CountryConfigExport;

export = CountryConfig;

interface Currency {
  id: string;
  symbol: string;
  description: string;
  decimal_places: number;
}

interface State {
  id: string;
  name: string;
}

interface GeoInformation {
  location: {
    latitude: number;
    longitude: number;
  };
}

declare namespace CountryConfig {
  export type CountryId = keyof typeof config & (string & {});

  export interface Country {
    id: CountryId;
    name: string;
    locale: string;
    currency_id: string;
    decimal_separator: string;
    thousands_separator: string;
    time_zone: string;
    time_zone_location: string;
    geo_information: GeoInformation;
    states: Array<State>;
    currencies: Record<string, Currency>;
  }
}
